func (s *Scanner) state0Ws() error {
	nextByte := s.source[s.lexemePeekIdx]
	switch {
	case nextByte == '\t':
		s.state = 1
	case nextByte == '\n':
		s.state = 1
	case nextByte == 0xb:
		s.state = 1
	case nextByte == 0xc:
		s.state = 1
	case nextByte == '\r':
		s.state = 2
	case nextByte == ' ':
		s.state = 1
	case nextByte == '"':
		s.state = 4
	case nextByte == '%':
		s.state = 6
	case nextByte == '\'':
		s.state = 8
	case nextByte == '.':
		s.state = 11
	case nextByte == '/':
		s.state = 3
	case '0' <= nextByte && nextByte <= '9':
		s.state = 16
	case nextByte == ':':
		s.state = 9
	case nextByte == ';':
		s.state = 14
	case nextByte == '<':
		s.state = 15
	case nextByte == '=':
		s.state = 10
	case 'A' <= nextByte && nextByte <= 'Z':
		s.state = 11
	case nextByte == '[':
		s.state = 12
	case nextByte == '_':
		s.state = 5
	case 'a' <= nextByte && nextByte <= 'z':
		s.state = 11
	case nextByte == '{':
		s.state = 7
	case nextByte == '|':
		s.state = 13
	default:
		return errInvalidByte
	}
	return nil
}

